   */
  isToolAvailable(name: string): boolean {
    const tool = this.tools.get(name);
    return tool?.status === 'connected' || false;
  }

  /**
   * Get tool functions
   */
  getToolFunctions(toolName: string): MCPFunction[] {
    const tool = this.tools.get(toolName);
    return tool?.functions || [];
  }

