+   */
+  async spawnAgentAsync(profile: AgentProfile): Promise<JobHandle> {
+    return this.jobManager.submitJob(
+      'agent:spawn',
+      profile,
+      async (input, onProgress) => {
+        onProgress(0);
+
+        // Initialize agent
+        const agent = await this.initializeAgent(input);
+        onProgress(30);
+
+        // Load capabilities
+        await agent.loadCapabilities();
+        onProgress(60);
